/*
 * Virtual Cluster VM Provisioning Simulation
 * Demonstrates: VM creation, resource allocation, and cluster management
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_HOSTS 10
#define MAX_VMS 100
#define MAX_VMS_PER_HOST 20

// VM states
typedef enum {
    VM_PENDING,
    VM_RUNNING,
    VM_MIGRATING,
    VM_STOPPED
} VMState;

// Virtual Machine structure
typedef struct {
    int vm_id;
    char hostname[32];
    int vcpus;
    int memory_mb;
    int storage_gb;
    VMState state;
    int host_id;  // -1 if not assigned
} VM;

// Physical Host structure
typedef struct {
    int host_id;
    char name[32];
    int total_vcpus;
    int total_memory_mb;
    int used_vcpus;
    int used_memory_mb;
    int vm_count;
    int vm_list[MAX_VMS_PER_HOST];
} Host;

// Virtual Cluster structure
typedef struct {
    Host hosts[MAX_HOSTS];
    VM vms[MAX_VMS];
    int host_count;
    int vm_count;
} VirtualCluster;

// Initialize a host
void init_host(Host *host, int id, const char *name, int vcpus, int memory_mb) {
    host->host_id = id;
    strcpy(host->name, name);
    host->total_vcpus = vcpus;
    host->total_memory_mb = memory_mb;
    host->used_vcpus = 0;
    host->used_memory_mb = 0;
    host->vm_count = 0;
}

// Check if host can accommodate a VM
int can_accommodate(Host *host, int vcpus, int memory_mb) {
    return (host->total_vcpus - host->used_vcpus >= vcpus &&
            host->total_memory_mb - host->used_memory_mb >= memory_mb &&
            host->vm_count < MAX_VMS_PER_HOST);
}

// Allocate VM to host
int allocate_vm_to_host(Host *host, int vm_id, int vcpus, int memory_mb) {
    if (!can_accommodate(host, vcpus, memory_mb)) {
        return 0; // Failed
    }
    host->used_vcpus += vcpus;
    host->used_memory_mb += memory_mb;
    host->vm_list[host->vm_count++] = vm_id;
    return 1; // Success
}

// Release VM from host
void release_vm_from_host(Host *host, int vm_id, int vcpus, int memory_mb) {
    host->used_vcpus -= vcpus;
    host->used_memory_mb -= memory_mb;
    host->vm_count--;
    // Remove from vm_list (simplified)
    for (int i = 0; i < host->vm_count; i++) {
        if (host->vm_list[i] == vm_id) {
            host->vm_list[i] = host->vm_list[host->vm_count];
            break;
        }
    }
}

// Find best host using "best fit" strategy
int find_best_host(VirtualCluster *cluster, int vcpus, int memory_mb) {
    int best_host = -1;
    int lowest_utilization = 100;

    for (int i = 0; i < cluster->host_count; i++) {
        Host *host = &cluster->hosts[i];
        if (can_accommodate(host, vcpus, memory_mb)) {
            int util = (host->used_vcpus * 100) / host->total_vcpus;
            if (util < lowest_utilization) {
                lowest_utilization = util;
                best_host = i;
            }
        }
    }
    return best_host;
}

// Provision a new VM
int provision_vm(VirtualCluster *cluster, int vcpus, int memory_mb, int storage_gb) {
    if (cluster->vm_count >= MAX_VMS) {
        printf("Error: Maximum VM limit reached\n");
        return -1;
    }

    // Find suitable host
    int host_idx = find_best_host(cluster, vcpus, memory_mb);
    if (host_idx == -1) {
        printf("Error: No host available with sufficient resources\n");
        return -1;
    }

    // Create VM
    VM *vm = &cluster->vms[cluster->vm_count];
    vm->vm_id = cluster->vm_count + 1;
    vm->vcpus = vcpus;
    vm->memory_mb = memory_mb;
    vm->storage_gb = storage_gb;
    vm->state = VM_RUNNING;
    vm->host_id = host_idx;

    // Allocate to host
    allocate_vm_to_host(&cluster->hosts[host_idx], vm->vm_id, vcpus, memory_mb);

    printf("VM-%d provisioned: %d vCPUs, %dMB RAM, %dGB Storage -> Host %s\n",
           vm->vm_id, vcpus, memory_mb, storage_gb, cluster->hosts[host_idx].name);

    cluster->vm_count++;
    return vm->vm_id;
}

// Simulate live migration
int migrate_vm(VirtualCluster *cluster, int vm_id, int dest_host_id) {
    if (vm_id <= 0 || vm_id > cluster->vm_count) {
        printf("Error: Invalid VM ID\n");
        return 0;
    }

    VM *vm = &cluster->vms[vm_id - 1];
    Host *src_host = &cluster->hosts[vm->host_id];
    Host *dest_host = &cluster->hosts[dest_host_id];

    if (!can_accommodate(dest_host, vm->vcpus, vm->memory_mb)) {
        printf("Error: Destination host cannot accommodate VM\n");
        return 0;
    }

    // Phase 1: Pre-copy (simulated)
    printf("Migration: Pre-copy phase for VM-%d...\n", vm_id);

    // Phase 2: Stop and copy
    vm->state = VM_MIGRATING;
    release_vm_from_host(src_host, vm_id, vm->vcpus, vm->memory_mb);
    allocate_vm_to_host(dest_host, vm_id, vm->vcpus, vm->memory_mb);

    // Phase 3: Switchover
    vm->host_id = dest_host_id;
    vm->state = VM_RUNNING;

    printf("Migration: VM-%d migrated from %s to %s\n",
           vm_id, src_host->name, dest_host->name);
    return 1;
}

// Print cluster status
void print_cluster_status(VirtualCluster *cluster) {
    printf("\n========== VIRTUAL CLUSTER STATUS ==========\n");
    printf("Total Hosts: %d | Total VMs: %d\n\n", cluster->host_count, cluster->vm_count);

    for (int i = 0; i < cluster->host_count; i++) {
        Host *h = &cluster->hosts[i];
        int cpu_util = (h->used_vcpus * 100) / h->total_vcpus;
        int mem_util = (h->used_memory_mb * 100) / h->total_memory_mb;

        printf("Host: %s\n", h->name);
        printf("  Resources: %d vCPUs, %dMB RAM\n", h->total_vcpus, h->total_memory_mb);
        printf("  Utilization: CPU=%d%%, RAM=%d%%\n", cpu_util, mem_util);
        printf("  VMs Running: %d\n", h->vm_count);
        printf("----------------------------------------\n");
    }
    printf("==========================================\n\n");
}

int main() {
    // Initialize virtual cluster
    VirtualCluster cluster;
    cluster.host_count = 3;
    cluster.vm_count = 0;

    // Create physical hosts
    init_host(&cluster.hosts[0], 0, "PHYS-01", 16, 32768);  // 16 vCPUs, 32GB
    init_host(&cluster.hosts[1], 1, "PHYS-02", 16, 32768);
    init_host(&cluster.hosts[2], 2, "PHYS-03", 16, 32768);

    printf("=== VIRTUAL CLUSTER PROVISIONING DEMO ===\n");

    // Provision VMs (simulating web tier)
    printf("\n--- Provisioning Web Tier ---\n");
    provision_vm(&cluster, 2, 4096, 50);   // VM-1
    provision_vm(&cluster, 2, 4096, 50);   // VM-2
    provision_vm(&cluster, 2, 4096, 50);   // VM-3

    // Provision VMs (simulating app tier)
    printf("\n--- Provisioning App Tier ---\n");
    provision_vm(&cluster, 4, 8192, 100);  // VM-4
    provision_vm(&cluster, 4, 8192, 100);  // VM-5

    // Provision VM (simulating database tier)
    printf("\n--- Provisioning DB Tier ---\n");
    provision_vm(&cluster, 8, 16384, 500);  // VM-6

    print_cluster_status(&cluster);

    // Demonstrate live migration
    printf("=== LIVE MIGRATION DEMO ===\n");
    migrate_vm(&cluster, 6, 2);  // Migrate VM-6 to PHYS-03

    print_cluster_status(&cluster);

    return 0;
}
